// The synthetic ensures has shape `(big_antecedent) ==> det_set_state_equal(...)`,
// where the antecedent is the (per-run) conjunction of every original
// `set_state` postcondition for both `(post1_self_, r1)` and `(post2_self_, r2)`.
// In the body those conjuncts are NOT free hypotheses — they're the LHS of the
// proof obligation's implication. To pull them into the proof context as
// assumptions, we wrap the entire proof in `if (antecedent) { ... }`. Outside
// the branch, the implication is vacuously true; inside it, every per-field
// `==`/`=~=` ensure, the two forall ensures, and the `wf()` facts are in scope.
//
// Inside the branch, the strategy is the same as for any "two ensures with
// disjoint triggers" gap:
//   1. Establish each Page-field equality at the *literal* `index as int`
//      (the syntactic form the unconditional ensures use), going through
//      `pre_self_.page_array@[index as int].FIELD` as the bridge between
//      run 1 and run 2.
//   2. Lift to whole-Page extensional equality at the literal index.
//   3. Lift to pointwise Page equality across the whole array by a
//      case-split inside `assert forall|i|`. For `i == index as int`, lift
//      step 2 via index-congruence; for `i != index`, fire each forall
//      ensure.
//   4. Use Seq extensionality (`=~=`) to lift pointwise equality to the
//      whole array view, which is what `det_set_state_equal` consumes.
// All non-`page_array` `PageAllocator` fields (free_pages_*, allocated_pages_*,
// mapped_pages_*, page_perms_*, container_map_*) are `==`-pinned by both
// runs to `pre_self_.<field>`, so equality between the two runs follows by
// SMT congruence — no extra hints needed.

if (post1_self_.page_array.wf())
    && (forall|i: int|
            #![trigger post1_self_.page_array@[i]]
            #![trigger pre_self_.page_array@[i]]
            #![trigger post1_self_.page_array@[i].ref_count]
            #![trigger pre_self_.page_array@[i].ref_count]
            0 <= i < NUM_PAGES && i != index ==>
                post1_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && (post1_self_.page_array@[index as int].addr
            =~= pre_self_.page_array@[index as int].addr)
    && (post1_self_.page_array@[index as int].is_io_page
            =~= pre_self_.page_array@[index as int].is_io_page)
    && (post1_self_.page_array@[index as int].rev_pointer
            =~= pre_self_.page_array@[index as int].rev_pointer)
    && (post1_self_.page_array@[index as int].ref_count
            =~= pre_self_.page_array@[index as int].ref_count)
    && (post1_self_.page_array@[index as int].owning_container
            =~= pre_self_.page_array@[index as int].owning_container)
    && (post1_self_.page_array@[index as int].mappings
            =~= pre_self_.page_array@[index as int].mappings)
    && (post1_self_.page_array@[index as int].io_mappings
            =~= pre_self_.page_array@[index as int].io_mappings)
    && (post1_self_.page_array@[index as int].state =~= state)
    && (post1_self_.free_pages_4k == pre_self_.free_pages_4k)
    && (post1_self_.free_pages_2m == pre_self_.free_pages_2m)
    && (post1_self_.free_pages_1g == pre_self_.free_pages_1g)
    && (post1_self_.allocated_pages_4k == pre_self_.allocated_pages_4k)
    && (post1_self_.allocated_pages_2m == pre_self_.allocated_pages_2m)
    && (post1_self_.allocated_pages_1g == pre_self_.allocated_pages_1g)
    && (post1_self_.mapped_pages_4k == pre_self_.mapped_pages_4k)
    && (post1_self_.mapped_pages_2m == pre_self_.mapped_pages_2m)
    && (post1_self_.mapped_pages_1g == pre_self_.mapped_pages_1g)
    && (post1_self_.page_perms_4k == pre_self_.page_perms_4k)
    && (post1_self_.page_perms_2m == pre_self_.page_perms_2m)
    && (post1_self_.page_perms_1g == pre_self_.page_perms_1g)
    && (post1_self_.container_map_4k == pre_self_.container_map_4k)
    && (post1_self_.container_map_2m == pre_self_.container_map_2m)
    && (post1_self_.container_map_1g == pre_self_.container_map_1g)
    && (post2_self_.page_array.wf())
    && (forall|i: int|
            #![trigger post2_self_.page_array@[i]]
            #![trigger pre_self_.page_array@[i]]
            #![trigger post2_self_.page_array@[i].ref_count]
            #![trigger pre_self_.page_array@[i].ref_count]
            0 <= i < NUM_PAGES && i != index ==>
                post2_self_.page_array@[i] =~= pre_self_.page_array@[i])
    && (post2_self_.page_array@[index as int].addr
            =~= pre_self_.page_array@[index as int].addr)
    && (post2_self_.page_array@[index as int].is_io_page
            =~= pre_self_.page_array@[index as int].is_io_page)
    && (post2_self_.page_array@[index as int].rev_pointer
            =~= pre_self_.page_array@[index as int].rev_pointer)
    && (post2_self_.page_array@[index as int].ref_count
            =~= pre_self_.page_array@[index as int].ref_count)
    && (post2_self_.page_array@[index as int].owning_container
            =~= pre_self_.page_array@[index as int].owning_container)
    && (post2_self_.page_array@[index as int].mappings
            =~= pre_self_.page_array@[index as int].mappings)
    && (post2_self_.page_array@[index as int].io_mappings
            =~= pre_self_.page_array@[index as int].io_mappings)
    && (post2_self_.page_array@[index as int].state =~= state)
    && (post2_self_.free_pages_4k == pre_self_.free_pages_4k)
    && (post2_self_.free_pages_2m == pre_self_.free_pages_2m)
    && (post2_self_.free_pages_1g == pre_self_.free_pages_1g)
    && (post2_self_.allocated_pages_4k == pre_self_.allocated_pages_4k)
    && (post2_self_.allocated_pages_2m == pre_self_.allocated_pages_2m)
    && (post2_self_.allocated_pages_1g == pre_self_.allocated_pages_1g)
    && (post2_self_.mapped_pages_4k == pre_self_.mapped_pages_4k)
    && (post2_self_.mapped_pages_2m == pre_self_.mapped_pages_2m)
    && (post2_self_.mapped_pages_1g == pre_self_.mapped_pages_1g)
    && (post2_self_.page_perms_4k == pre_self_.page_perms_4k)
    && (post2_self_.page_perms_2m == pre_self_.page_perms_2m)
    && (post2_self_.page_perms_1g == pre_self_.page_perms_1g)
    && (post2_self_.container_map_4k == pre_self_.container_map_4k)
    && (post2_self_.container_map_2m == pre_self_.container_map_2m)
    && (post2_self_.container_map_1g == pre_self_.container_map_1g)
{
    // ---- Step 1: per-Page-field equalities at the LITERAL `index as int` ----
    // Use the same `=~=` form the unconditional ensures use so triggers match.
    // Bridge run 1 -> pre and run 2 -> pre; transitivity then gives run 1 -> run 2.

    assert(post1_self_.page_array@[index as int].addr
        =~= pre_self_.page_array@[index as int].addr);
    assert(post2_self_.page_array@[index as int].addr
        =~= pre_self_.page_array@[index as int].addr);
    assert(post1_self_.page_array@[index as int].addr
        == post2_self_.page_array@[index as int].addr);

    assert(post1_self_.page_array@[index as int].is_io_page
        =~= pre_self_.page_array@[index as int].is_io_page);
    assert(post2_self_.page_array@[index as int].is_io_page
        =~= pre_self_.page_array@[index as int].is_io_page);
    assert(post1_self_.page_array@[index as int].is_io_page
        == post2_self_.page_array@[index as int].is_io_page);

    assert(post1_self_.page_array@[index as int].rev_pointer
        =~= pre_self_.page_array@[index as int].rev_pointer);
    assert(post2_self_.page_array@[index as int].rev_pointer
        =~= pre_self_.page_array@[index as int].rev_pointer);
    assert(post1_self_.page_array@[index as int].rev_pointer
        == post2_self_.page_array@[index as int].rev_pointer);

    assert(post1_self_.page_array@[index as int].ref_count
        =~= pre_self_.page_array@[index as int].ref_count);
    assert(post2_self_.page_array@[index as int].ref_count
        =~= pre_self_.page_array@[index as int].ref_count);
    assert(post1_self_.page_array@[index as int].ref_count
        == post2_self_.page_array@[index as int].ref_count);

    assert(post1_self_.page_array@[index as int].owning_container
        =~= pre_self_.page_array@[index as int].owning_container);
    assert(post2_self_.page_array@[index as int].owning_container
        =~= pre_self_.page_array@[index as int].owning_container);
    assert(post1_self_.page_array@[index as int].owning_container
        == post2_self_.page_array@[index as int].owning_container);

    assert(post1_self_.page_array@[index as int].mappings
        =~= pre_self_.page_array@[index as int].mappings);
    assert(post2_self_.page_array@[index as int].mappings
        =~= pre_self_.page_array@[index as int].mappings);
    assert(post1_self_.page_array@[index as int].mappings
        =~= post2_self_.page_array@[index as int].mappings);

    assert(post1_self_.page_array@[index as int].io_mappings
        =~= pre_self_.page_array@[index as int].io_mappings);
    assert(post2_self_.page_array@[index as int].io_mappings
        =~= pre_self_.page_array@[index as int].io_mappings);
    assert(post1_self_.page_array@[index as int].io_mappings
        =~= post2_self_.page_array@[index as int].io_mappings);

    assert(post1_self_.page_array@[index as int].state =~= state);
    assert(post2_self_.page_array@[index as int].state =~= state);
    assert(post1_self_.page_array@[index as int].state
        == post2_self_.page_array@[index as int].state);

    // ---- Step 2: whole-Page extensional equality at the literal index ----
    assert(post1_self_.page_array@[index as int]
        =~= post2_self_.page_array@[index as int]);

    // ---- Step 3: pointwise Page equality across all valid indices ----
    assert forall|i: int| 0 <= i < NUM_PAGES implies
        post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
        if i == index as int {
            // Lift the literal-index Page equality via index-congruence.
            assert(post1_self_.page_array@[i]
                == post1_self_.page_array@[index as int]);
            assert(post2_self_.page_array@[i]
                == post2_self_.page_array@[index as int]);
        } else {
            // i != index: each run's forall ensure pins post@[i] to pre@[i].
            assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
            assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        }
    };

    // ---- Step 4: Seq extensionality on the array view ----
    assert(post1_self_.page_array@ =~= post2_self_.page_array@);
}
